def _decode(name: str) -> str:
    data = _B64_GZ[name]
    blob = base64.b64decode(data.encode('ascii'))
    return gzip.decompress(blob).decode('utf-8')

def stress_classic_xml_buffers(num_paths: int = 100) -> dict[str, str]:
    names = ['pricingengine.xml','todaysmarket.xml','curveconfig.xml','simulation.xml','conventions.xml','counterparty.xml','netting.xml']
    out = {k: _decode(k) for k in names}
    sim = out.get('simulation.xml', '')
    if num_paths > 0 and sim:
        sim = re.sub(r'(<Samples>)([^<]+)(</Samples>)', rf'\g<1>{num_paths}\g<3>', sim, count=1)
        out['simulation.xml'] = sim
    return out

def stress_classic_market_lines() -> list[str]:
    return [ln.strip() for ln in _decode('market_data.txt').splitlines() if ln.strip() and not ln.strip().startswith('#')]

def stress_classic_fixing_lines() -> list[str]:
    return [ln.strip() for ln in _decode('fixings_data.txt').splitlines() if ln.strip() and not ln.strip().startswith('#')]
